// src/screens/GoalDetailsScreen.jsx
import React from 'react';
import { ChevronLeft, TrendingUp, History, MoreHorizontal, ArrowUpCircle } from 'lucide-react';
import { useCurrency } from "../context/CurrencyContext";


/**
 * GoalDetailsScreen Component
 * Detailed view of a specific goal with management options.
 */
const GoalDetailsScreen = ({ goal, onBack, onAddFunds, onWithdraw }) => {
  const { currencySymbol } = React.useContext(CurrencyContext); // Dynamic currency

  const activeGoal = goal || { title: 'Dream House', target: 50000, saved: 12500, color: 'bg-emerald-500' };
  const percentage = (activeGoal.saved / activeGoal.target) * 100;

  // Mock recent savings
  const recentSavings = [
    { date: 'Today, 10:00 AM', amount: 200, label: 'Auto-save' },
    { date: 'Jan 28, 2026', amount: 1500, label: 'Manual Top-up' }
  ];

  return (
    <div className="flex flex-col h-full bg-white animate-in slide-in-from-bottom duration-500">
      {/* Header */}
      <div className="flex items-center justify-between px-6 py-4 sticky top-0 bg-white z-10">
        <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
          <ChevronLeft className="w-6 h-6 text-gray-800" />
        </button>
        <h1 className="text-xl font-black text-gray-900">Goal Progress</h1>
        <button className="p-2 hover:bg-gray-100 rounded-full">
          <MoreHorizontal className="w-6 h-6 text-gray-400" />
        </button>
      </div>

      {/* Body */}
      <div className="p-6 flex-1 overflow-y-auto scrollbar-hide">
        {/* Goal Title & Progress */}
        <div className="text-center mb-10">
          <h2 className="text-3xl font-black text-gray-900 mb-2">{activeGoal.title}</h2>
          <div className="flex justify-center items-baseline gap-2">
            <span className="text-4xl font-black text-[#00875A]">
              {currencySymbol}{activeGoal.saved.toLocaleString()}
            </span>
            <span className="text-gray-400 font-bold">
              / {currencySymbol}{activeGoal.target.toLocaleString()}
            </span>
          </div>
        </div>

        {/* Big Progress Bar */}
        <div className="relative w-full h-4 bg-gray-100 rounded-full mb-12 overflow-hidden shadow-inner">
          <div 
            className={`h-full ${activeGoal.color} rounded-full transition-all duration-1000 shadow-lg`}
            style={{ width: `${percentage}%` }}
          />
          <div className="absolute top-6 right-0 text-[10px] font-black text-gray-400 uppercase tracking-widest">
            {Math.round(percentage)}% toward target
          </div>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-2 gap-4 mb-8">
          <div className="p-5 bg-gray-50 rounded-[2rem] border border-gray-100">
            <TrendingUp className="text-emerald-500 mb-3" size={20} />
            <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest mb-1">Monthly Avg</p>
            <p className="text-lg font-black text-gray-800">{currencySymbol}1,240.00</p>
          </div>
          <div className="p-5 bg-gray-50 rounded-[2rem] border border-gray-100">
            <History className="text-blue-500 mb-3" size={20} />
            <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest mb-1">Days Left</p>
            <p className="text-lg font-black text-gray-800">142 Days</p>
          </div>
        </div>

        {/* Recent Savings */}
        <h4 className="text-sm font-black text-gray-900 mb-4 uppercase tracking-widest ml-1">Recent Savings</h4>
        <div className="space-y-4">
          {recentSavings.map((item, i) => (
            <div key={i} className="flex justify-between items-center p-4 bg-gray-50/50 rounded-2xl">
              <div>
                <p className="font-black text-gray-800 text-sm">{item.label}</p>
                <p className="text-[10px] text-gray-400 font-bold uppercase">{item.date}</p>
              </div>
              <p className="font-black text-emerald-600">+{currencySymbol}{item.amount.toLocaleString()}</p>
            </div>
          ))}
        </div>
      </div>

      {/* Footer Actions */}
      <div className="p-6 bg-white border-t border-gray-50 flex flex-col gap-4">
        <button 
          onClick={onAddFunds}
          className="w-full py-4 rounded-2xl font-black text-white bg-[#00875A] shadow-lg flex items-center justify-center gap-3 active:scale-[0.98] transition-all"
        >
          <ArrowUpCircle size={20} />
          Add Funds to Goal
        </button>
        <button
          onClick={onWithdraw}
          className="w-full py-4 rounded-2xl font-black text-white bg-red-600 shadow-lg flex items-center justify-center gap-3 active:scale-[0.98] transition-all"
        >
          <ArrowUpCircle size={20} />
          Withdraw from Goal
        </button>
      </div>
    </div>
  );
};

export default GoalDetailsScreen;
